mapper.select:
select issue_status_id, user_id, status_name, status_answer, closed_yn from issue_status where user_id = #{userId}
and upper(status_name) like '%' || upper(#{statusName}) || '%'
and closed_yn = #{closedYn}
order by issue_status_id ASC

mapper.update:
update issue_status
set
status_name = #{statusName},
status_answer = #{statusAnswer},
closed_yn = #{closedYn}
where issue_status_id = #{issueStatusId}
and user_id = #{userId}

mapper.delete:
delete from issue_status
where issue_status_id = #{issueStatusId}
and user_id = #{userId}

mapper.select:
select count(*)
from issue_status
where user_id = #{userId}
and status_name = #{statusName}

	and issue_status_id != #{issueStatusId}

select count(*)
from (
select issue_status_id
from issue
where issue_status_id = #{issueStatusId}

union all

select initial_status_id
from issue_type
where initial_status_id = #{issueStatusId}

union all

select from_status_id
from workflow_transition
where from_status_id = #{issueStatusId}

union all

